modules.fpm_unpack:
`timescale 1ns/1ps
module fpm_unpack(
    input  [31:0] a,
    input  [31:0] b,
    output        a_sign,
    output [7:0]  a_exp,
    output [23:0] a_mant,
    output        b_sign,
    output [7:0]  b_exp,
    output [23:0] b_mant,
    output        a_is_nan,
    output        a_is_inf,
    output        a_is_zero,
    output        b_is_nan,
    output        b_is_inf,
    output        b_is_zero
);

    // Extract fields from a
    wire a_sign_bit = a[31];
    wire [7:0] a_exp_bits = a[30:23];
    wire [22:0] a_mant_bits = a[22:0];

    // Extract fields from b
    wire b_sign_bit = b[31];
    wire [7:0] b_exp_bits = b[30:23];
    wire [22:0] b_mant_bits = b[22:0];

    // Detect special cases for a
    wire a_is_zero_val = (a_exp_bits == 8'b0) & (a_mant_bits == 23'b0);
    wire a_is_inf_val = (a_exp_bits == 8'hFF) & (a_mant_bits == 23'b0);
    wire a_is_nan_val = (a_exp_bits == 8'hFF) & (a_mant_bits != 23'b0);

    // Detect special cases for b
    wire b_is_zero_val = (b_exp_bits == 8'b0) & (b_mant_bits == 23'b0);
    wire b_is_inf_val = (b_exp_bits == 8'hFF) & (b_mant_bits == 23'b0);
    wire b_is_nan_val = (b_exp_bits == 8'hFF) & (b_mant_bits != 23'b0);

    // Add implicit leading 1 for normalized numbers (exp != 0 and exp != 255)
    wire a_is_normalized = (a_exp_bits != 8'b0) & (a_exp_bits != 8'hFF);
    wire b_is_normalized = (b_exp_bits != 8'b0) & (b_exp_bits != 8'hFF);

    wire [23:0] a_mant_val = a_is_normalized ? {1'b1, a_mant_bits} : {1'b0, a_mant_bits};
    wire [23:0] b_mant_val = b_is_normalized ? {1'b1, b_mant_bits} : {1'b0, b_mant_bits};

    // Assign outputs for a
    assign a_sign = a_sign_bit;
    assign a_exp = a_exp_bits;
    assign a_mant = a_mant_val;
    assign a_is_nan = a_is_nan_val;
    assign a_is_inf = a_is_inf_val;
    assign a_is_zero = a_is_zero_val;

    // Assign outputs for b
    assign b_sign = b_sign_bit;
    assign b_exp = b_exp_bits;
    assign b_mant = b_mant_val;
    assign b_is_nan = b_is_nan_val;
    assign b_is_inf = b_is_inf_val;
    assign b_is_zero = b_is_zero_val;

endmodule

modules.fpm_multiply:
`timescale 1ns/1ps
module fpm_multiply(
    input         a_sign,
    input  [7:0]  a_exp,
    input  [23:0] a_mant,
    input         b_sign,
    input  [7:0]  b_exp,
    input  [23:0] b_mant,
    output        result_sign,
    output [47:0] product,
    output [9:0]  raw_exp
);
    // Sign is XOR of input signs
    assign result_sign = a_sign ^ b_sign;

    // Exponent: subtract bias once during addition
    // result_exp = (a_exp - 127) + (b_exp - 127) + 127 = a_exp + b_exp - 127
    wire [9:0] exp_sum;
    assign exp_sum = {1'b0, a_exp} + {1'b0, b_exp} - 10'd127;
    assign raw_exp = exp_sum;

    // Mantissa multiplication: (1.a_mant) × (1.b_mant)
    // Treat 24-bit mantissa as fractional part after implicit leading 1
    // (1 + a_mant/2^24) * (1 + b_mant/2^24)
    // Multiply as integers treating implicit 1 as 2^24:
    // (2^24 + a_mant) * (2^24 + b_mant) = 2^48 + a_mant*2^24 + b_mant*2^24 + a_mant*b_mant

    wire [47:0] mant_a_scaled;  // a_mant in 48-bit with implicit 1
    wire [47:0] mant_b_scaled;  // b_mant in 48-bit with implicit 1

    assign mant_a_scaled = {1'b1, a_mant};  // 1.a_mant as 48-bit (bit 47 is the 1, bits 46:23 are a_mant)
    assign mant_b_scaled = {1'b1, b_mant};  // 1.b_mant as 48-bit

    wire [95:0] full_product;
    assign full_product = mant_a_scaled * mant_b_scaled;  // 48×48 = 96-bit product

    // The product is in range [1, 4) in 48-bit fixed point
    // Bits [95:48] contain the integer part, bits [47:0] contain the fractional part
    // We want to return the normalized 48-bit mantissa (bits [47:0] of the result after normalization)
    // Since product is 96-bit and we want 48-bit output with implicit leading 1,
    // we take bits [95:48] which gives us the result with leading 1 in the implicit position

    assign product = full_product[95:48];

endmodule

modules.fpm_normalize:
`timescale 1ns/1ps
module fpm_normalize(
    input  [47:0] product,
    input  [9:0]  raw_exp,
    output [22:0] norm_frac,
    output [9:0]  norm_exp,
    output        guard,
    output        sticky
);
    wire needs_shift;

    // Check if bit 47 is set (product >= 2.0 in normalized form)
    assign needs_shift = product[47];

    // Fraction extraction:
    // If shift needed (bit 47 = 1): frac = bits [46:24]
    // If no shift (bit 47 = 0): frac = bits [45:23]
    assign norm_frac = needs_shift ? product[46:24] : product[45:23];

    // Exponent adjustment
    assign norm_exp = needs_shift ? (raw_exp + 10'd1) : raw_exp;

    // Guard bit:
    // If shift needed: guard = bit 23
    // If no shift: guard = bit 22
    assign guard = needs_shift ? product[23] : product[22];

    // Sticky bit (OR of all remaining bits):
    // If shift needed: sticky = OR(bits[22:0])
    // If no shift: sticky = OR(bits[21:0])
    assign sticky = needs_shift ? 
                    (|product[22:0]) : 
                    (|product[21:0]);

endmodule

modules.fpm_round_pack:
`timescale 1ns/1ps
module fpm_round_pack(
    input         sign,
    input  [22:0] norm_frac,
    input  [9:0]  norm_exp,
    input         guard,
    input         sticky,
    output reg [31:0] result,
    output reg        overflow,
    output reg        underflow
);

    always @(*) begin
        overflow = 0;
        underflow = 0;
        result = 0;

        // Check for special cases
        if (norm_exp == 10'd0) begin
            // Underflow: exponent is 0
            underflow = 1;
            result = {sign, 31'd0};  // Return signed zero
        end
        else if (norm_exp >= 10'd255) begin
            // Overflow: exponent is 255 or greater
            overflow = 1;
            // Return signed infinity
            result = {sign, 8'b11111111, 23'd0};
        end
        else begin
            // Normal case: pack the number
            // We need to handle rounding with the implicit leading 1
            reg [23:0] mantissa_with_implicit;
            reg [23:0] rounded_mantissa;
            reg [9:0] rounded_exp;

            mantissa_with_implicit = {1'b1, norm_frac};  // Add implicit leading 1
            rounded_mantissa = mantissa_with_implicit;
            rounded_exp = norm_exp;

            // Rounding logic (round to nearest, ties to even)
            // Round up if guard=1 and (sticky=1 or lsb=1)
            if (guard & (sticky | mantissa_with_implicit[0])) begin
                rounded_mantissa = mantissa_with_implicit + 1;
                // Check if mantissa overflowed (24-bit overflow)
                if (rounded_mantissa[23] == 1'b0) begin
                    // Mantissa overflowed past 24 bits, increment exponent
                    rounded_exp = norm_exp + 1;
                    // Check if this caused overflow to exponent 255
                    if (rounded_exp >= 10'd255) begin
                        overflow = 1;
                        result = {sign, 8'b11111111, 23'd0};  // Return infinity
                    end
                    else begin
                        // After overflow, mantissa is 1.0, so frac is all 0s
                        result = {sign, rounded_exp[7:0], 23'd0};
                    end
                end
                else begin
                    // Normal case: use the lower 23 bits as fraction
                    result = {sign, rounded_exp[7:0], rounded_mantissa[22:0]};
                end
            end
            else begin
                result = {sign, rounded_exp[7:0], norm_frac};
            end
        end
    end

endmodule
